/**
 * test-issue-1668-m4-per-route.js
 *
 * Milestone 4 of #1668 — per-route polish. Targets the route-specific
 * residuals that M2 (color tokens) and M3 (typography floor) didn't catch:
 *
 *   - td.hash-cell + variants (collision / taken / possible / empty)
 *   - span.badge.badge-${type} (generated by public/roles.js syncBadgeColors)
 *   - .path-hops .hop-named (chip floor + on-accent token)
 *   - .alab-pkt (font-weight floor against alab background)
 *   - /live controls: .vcr-btn, .vcr-scope-btn, .vcr-live-btn,
 *                     .live-title, .live-feed-empty, .nav-drawer-title
 *
 * Two-layer check:
 *   1) CSS-rule scan — fs/fw floor (mirrors M3 helpers).
 *   2) Badge contrast — extract TYPE_COLORS from public/roles.js and
 *      verify each emitted badge class meets WCAG AA against the FG/BG
 *      that syncBadgeColors() will write.
 */

'use strict';

const fs = require('fs');
const path = require('path');
const assert = require('assert');

const repoRoot = __dirname;
const cssPath = path.join(repoRoot, 'public', 'style.css');
const liveCssPath = path.join(repoRoot, 'public', 'live.css');
const audioLabJsPath = path.join(repoRoot, 'public', 'audio-lab.js');
const rolesJsPath = path.join(repoRoot, 'public', 'roles.js');
const css = fs.readFileSync(cssPath, 'utf8');
const liveCss = fs.readFileSync(liveCssPath, 'utf8');
const audioLabJs = fs.readFileSync(audioLabJsPath, 'utf8');
const rolesJs = fs.readFileSync(rolesJsPath, 'utf8');

// --- helpers (mirrors M3 test) ---------------------------------------------

function resolveFontSizePx(value, allCss) {
  if (!value) return NaN;
  const v = value.trim();
  let m = v.match(/^([0-9.]+)px$/);
  if (m) return parseFloat(m[1]);
  m = v.match(/^([0-9.]+)rem$/);
  if (m) return parseFloat(m[1]) * 16;
  m = v.match(/^clamp\(\s*([0-9.]+)(px|rem)\s*,/);
  if (m) return m[2] === 'rem' ? parseFloat(m[1]) * 16 : parseFloat(m[1]);
  m = v.match(/^var\(\s*(--[a-z0-9-]+)\s*\)$/i);
  if (m) {
    const tok = m[1];
    const re = new RegExp(`${tok}\\s*:\\s*([^;]+);`);
    const def = allCss.match(re);
    if (def) return resolveFontSizePx(def[1].trim(), allCss);
  }
  return NaN;
}

function resolveFontWeight(value, allCss) {
  if (!value) return NaN;
  const v = value.trim();
  if (/^\d+$/.test(v)) return parseInt(v, 10);
  if (v === 'normal') return 400;
  if (v === 'bold') return 700;
  const m = v.match(/^var\(\s*(--[a-z0-9-]+)\s*\)$/i);
  if (m) {
    const tok = m[1];
    const re = new RegExp(`${tok}\\s*:\\s*([^;]+);`);
    const def = allCss.match(re);
    if (def) return resolveFontWeight(def[1].trim(), allCss);
  }
  return NaN;
}

function parseDecl(body, prop) {
  const re = new RegExp(`(?:^|;|\\{|\\s)${prop}\\s*:\\s*([^;{}]+)`, 'i');
  const m = body.match(re);
  return m ? m[1].trim() : null;
}

function stripMediaQueries(cssText) {
  // Remove @media blocks (viewport-scoped overrides). M4 typography floor
  // asserts the BASE/desktop rule; per-viewport overrides (e.g. .vcr-btn
  // mobile carve-out at max-width:640px, see #1668-M4 r3 / #1221) are out
  // of scope for the desktop-base contrast/typography gate. Strip CSS
  // comments first so '@media' text in comments doesn't confuse matching.
  cssText = cssText.replace(/\/\*[\s\S]*?\*\//g, '');
  let out = '';
  let i = 0;
  while (i < cssText.length) {
    const idx = cssText.indexOf('@media', i);
    if (idx === -1) { out += cssText.slice(i); break; }
    out += cssText.slice(i, idx);
    const open = cssText.indexOf('{', idx);
    if (open === -1) { out += cssText.slice(idx); break; }
    let depth = 1;
    let j = open + 1;
    while (j < cssText.length && depth > 0) {
      const c = cssText[j];
      if (c === '{') depth++;
      else if (c === '}') depth--;
      j++;
    }
    i = j;
  }
  return out;
}

function effective(selector, cssText) {
  cssText = stripMediaQueries(cssText);
  const re = /([^{}]*)\{([^}]*)\}/g;
  let fsRaw = null;
  let fwRaw = null;
  let m;
  while ((m = re.exec(cssText)) !== null) {
    let selList = m[1].trim();
    selList = selList.replace(/\/\*[\s\S]*?\*\//g, '').trim();
    if (!selList || selList.startsWith('@')) continue;
    const sels = selList.split(',').map((s) => s.trim());
    const hit = sels.some((s) => {
      if (s === selector) return true;
      if (s.startsWith(selector + ':')) return true;
      return false;
    });
    if (!hit) continue;
    const fs2 = parseDecl(m[2], 'font-size');
    const fw2 = parseDecl(m[2], 'font-weight');
    if (fs2) fsRaw = fs2;
    if (fw2) fwRaw = fw2;
  }
  return {
    fontSize: resolveFontSizePx(fsRaw, cssText),
    fontWeight: resolveFontWeight(fwRaw, cssText),
  };
}

function passesFloor(fs, fw) {
  if (Number.isNaN(fs)) return false;
  if (fs >= 14) return true;
  if (fs >= 12 && !Number.isNaN(fw) && fw >= 500) return true;
  return false;
}

// --- contrast helpers ------------------------------------------------------

function hexToRgb(hex) {
  const h = hex.replace('#', '');
  return [
    parseInt(h.slice(0, 2), 16),
    parseInt(h.slice(2, 4), 16),
    parseInt(h.slice(4, 6), 16),
  ];
}

function relLum([r, g, b]) {
  const lin = (v) => {
    const s = v / 255;
    return s <= 0.03928 ? s / 12.92 : Math.pow((s + 0.055) / 1.055, 2.4);
  };
  return 0.2126 * lin(r) + 0.7152 * lin(g) + 0.0722 * lin(b);
}

function contrast(fg, bg) {
  const l1 = relLum(fg);
  const l2 = relLum(bg);
  const [a, b] = l1 > l2 ? [l1, l2] : [l2, l1];
  return (a + 0.05) / (b + 0.05);
}

// --- 1) CSS rule floor checks ---------------------------------------------

const RULE_TARGETS = [
  // hash-cell carve-outs M4 adds — base rule must lock font-weight floor
  ['.hash-cell',                 css,     'analytics hash-grid base — needs >=500 weight'],
  ['.hash-cell-collision',       css,     'analytics collision cell — semantic carve-out'],
  ['.hash-cell-taken',           css,     'analytics taken cell — semantic carve-out'],
  ['.hash-cell-possible',        css,     'analytics possible cell — semantic carve-out'],
  // alab packet rows — M3 cleared font-size 12, M4 enforces weight floor
  ['.alab-pkt',                  audioLabJs, 'audio-lab packet row — needs >=500 weight'],
  // /live controls
  ['.vcr-btn',                   liveCss, 'live VCR transport buttons'],
  ['.vcr-scope-btn',             liveCss, 'live VCR scope chips (1h/6h/12h/24h)'],
  ['.vcr-live-btn',              liveCss, 'live LIVE indicator chip'],
  ['.live-title',                liveCss, 'MESH LIVE title'],
  ['.live-feed-empty',           liveCss, 'live empty-feed placeholder'],
  ['.nav-drawer-title',          css,     'nav drawer title'],
  // path-hops chips — M2 token reuse: verify floor still holds
  ['.path-hops .hop-named',      css,     'path-hop named chip — base floor'],
];

let ruleFails = 0;
const ruleRows = [];
for (const [sel, src, note] of RULE_TARGETS) {
  const e = effective(sel, src);
  const ok = passesFloor(e.fontSize, e.fontWeight);
  ruleRows.push({ sel, fs: e.fontSize, fw: e.fontWeight, ok, note });
  if (!ok) ruleFails++;
}

console.log('M4 per-route typography floor:');
console.log('--------------------------------------------------');
for (const r of ruleRows) {
  const status = r.ok ? 'PASS' : 'FAIL';
  console.log(
    `  [${status}] ${r.sel.padEnd(28)}  fs=${String(r.fs).padEnd(6)}  fw=${String(r.fw).padEnd(5)}  (${r.note})`
  );
}
console.log('--------------------------------------------------');

// --- 2) Badge contrast check from roles.js TYPE_COLORS --------------------

const tcMatch = rolesJs.match(/TYPE_COLORS\s*=\s*\{([\s\S]*?)\};/);
assert.ok(tcMatch, 'TYPE_COLORS not found in roles.js');
const typeColors = {};
const entryRe = /(\w+)\s*:\s*'(#[0-9a-f]{6})'/gi;
let mm;
while ((mm = entryRe.exec(tcMatch[1])) !== null) {
  typeColors[mm[1]] = mm[2];
}

// Anti-tautology: actually EXECUTE syncBadgeColors in a sandbox and read
// the emitted CSS, rather than pattern-matching the source. The contract
// is: for every TYPE in TYPE_BADGE_MAP, the emitted `.badge-${cls}` rule
// must produce a (fg,bg) pair that clears WCAG AA (>=4.5:1).

const vm = require('vm');

// Minimal DOM stub — syncBadgeColors only touches document.getElementById
// / createElement / head.appendChild and sets textContent on the <style>.
let emittedCss = '';
const styleStub = { set textContent(v) { emittedCss = v; }, get textContent() { return emittedCss; } };
const sandbox = {
  window: { TYPE_COLORS: { ...typeColors } },
  document: {
    getElementById: () => null,
    createElement: () => styleStub,
    head: { appendChild: () => {} },
    readyState: 'complete',
    addEventListener: () => {},
  },
  Object,
  console,
};
sandbox.window.document = sandbox.document;

// Wrap roles.js in a function scope so its top-level IIFE / var decls
// resolve against our sandbox `window`. The file has an outer
// `(function(){ ... })();` wrapper — running it in the sandbox is enough.
vm.createContext(sandbox);
try {
  vm.runInContext(rolesJs, sandbox, { filename: 'public/roles.js', timeout: 5000 });
} catch (e) {
  // Some references (URL, Proxy on DOM) may throw — we only need
  // syncBadgeColors to exist. Re-eval just the syncBadgeColors block if
  // the full file blew up.
  console.warn('roles.js sandbox load warning:', e.message);
}

assert.ok(typeof sandbox.window.syncBadgeColors === 'function', 'syncBadgeColors not exposed on window after sandbox load');

// Trigger emission.
emittedCss = '';
sandbox.window.syncBadgeColors();
assert.ok(emittedCss.length > 0, 'syncBadgeColors emitted no CSS');

function parseRgbFromCss(token) {
  token = token.trim();
  let m = token.match(/^#([0-9a-f]{6})$/i);
  if (m) {
    return [parseInt(m[1].slice(0,2),16), parseInt(m[1].slice(2,4),16), parseInt(m[1].slice(4,6),16)];
  }
  m = token.match(/^rgb\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)\s*\)$/);
  if (m) return [+m[1], +m[2], +m[3]];
  return null;
}

const TYPE_BADGE_MAP_LOCAL = {
  ADVERT: 'advert', GRP_TXT: 'grp-txt', GRP_DATA: 'grp-data', TXT_MSG: 'txt-msg', ACK: 'ack',
  REQ: 'req', RESPONSE: 'response', TRACE: 'trace', PATH: 'path',
  ANON_REQ: 'anon-req', MULTIPART: 'multipart', CONTROL: 'control', RAW_CUSTOM: 'raw-custom',
  UNKNOWN: 'unknown',
};

let badgeFails = 0;
const badgeRows = [];
for (const type of Object.keys(typeColors)) {
  const cls = TYPE_BADGE_MAP_LOCAL[type] || type.toLowerCase();
  const ruleRe = new RegExp(`\\.badge-${cls.replace(/[-]/g,'\\-')}\\s*\\{([^}]+)\\}`, 'i');
  const m = emittedCss.match(ruleRe);
  if (!m) {
    badgeRows.push({ type, cls, ratio: NaN, ok: false, reason: 'rule not emitted' });
    badgeFails++;
    continue;
  }
  const body = m[1];
  const bgRaw = (body.match(/background(?:-color)?\s*:\s*([^;]+)/i) || [, ''])[1].trim();
  const fgRaw = (body.match(/(?:^|;|\s)color\s*:\s*([^;]+)/i) || [, ''])[1].trim();
  const bg = parseRgbFromCss(bgRaw);
  const fg = parseRgbFromCss(fgRaw);
  if (!bg || !fg) {
    badgeRows.push({ type, cls, ratio: NaN, ok: false, reason: `unparsed fg=${fgRaw} bg=${bgRaw}` });
    badgeFails++;
    continue;
  }
  const ratio = +contrast(fg, bg).toFixed(2);
  const ok = ratio >= 4.5;
  badgeRows.push({ type, cls, ratio, ok, fg: `rgb(${fg.join(',')})`, bg: `rgb(${bg.join(',')})` });
  if (!ok) badgeFails++;
}

console.log('\nM4 badge contrast (live-executed syncBadgeColors output):');
console.log('--------------------------------------------------');
for (const r of badgeRows) {
  console.log(
    `  [${r.ok ? 'PASS' : 'FAIL'}] badge-${r.cls.padEnd(12)} bg=${r.bg || '?'}  fg=${r.fg || '?'}  ratio=${r.ratio}${r.reason ? ' '+r.reason : ''}`
  );
}
console.log('--------------------------------------------------');

function type_to_cls(t) { return t; } // (unused — kept for log compatibility)

// --- 3) hash-cell carve-out — collision / taken / possible must keep distinct
//        bgs AND each must clear WCAG AA (>=4.5:1) against the #fff fg they
//        ship with. (#1681 r1 adv-#5: prior version only asserted bgTak≠bgPos,
//        which let 2.28:1 / 1.92:1 / 3.96:1 BLOCKERs through.)

const colMatch = css.match(/\.hash-cell-collision\s*\{([^}]+)\}/);
const takMatch = css.match(/\.hash-cell-taken\s*\{([^}]+)\}/);
const posMatch = css.match(/\.hash-cell-possible\s*\{([^}]+)\}/);
assert.ok(colMatch, 'hash-cell-collision rule missing');
assert.ok(takMatch, 'hash-cell-taken rule missing');
assert.ok(posMatch, 'hash-cell-possible rule missing');

function bgOf(body) {
  const m = body.match(/background(?:-color)?\s*:\s*([^;]+)/);
  return m ? m[1].trim() : null;
}
const bgCol = bgOf(colMatch[1]);
const bgTak = bgOf(takMatch[1]);
const bgPos = bgOf(posMatch[1]);

// Encoding preservation: taken and possible must remain visually distinct.
assert.notStrictEqual(bgTak, bgPos, 'hash-cell taken/possible bgs collapsed — semantic encoding lost');

// Color-value parsing — accept #hex or rgb()/rgba() literal. Reject var()
// indirection here: M4 r1 requires that hash-cell bgs are an own carve-out,
// because the --status-{green,yellow} tokens are too light vs #fff.
function parseColor(val) {
  if (!val) return null;
  const v = val.trim();
  let m = v.match(/^#([0-9a-fA-F]{6})$/);
  if (m) return hexToRgb('#' + m[1]);
  m = v.match(/^#([0-9a-fA-F]{3})$/);
  if (m) {
    const s = m[1];
    return hexToRgb('#' + s[0]+s[0]+s[1]+s[1]+s[2]+s[2]);
  }
  m = v.match(/^rgba?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
  if (m) return [parseInt(m[1],10), parseInt(m[2],10), parseInt(m[3],10)];
  return null;
}

const WHITE = [255,255,255];
const AA = 4.5;

// taken — base CSS rule must declare the bg
const takRgb = parseColor(bgTak);
assert.ok(takRgb, `hash-cell-taken bg "${bgTak}" must be a #hex or rgb() literal (var() not allowed — needs own contrast budget vs #fff)`);
const takRatio = contrast(WHITE, takRgb);
assert.ok(takRatio >= AA, `hash-cell-taken bg ${bgTak} vs #fff = ${takRatio.toFixed(2)}:1 < ${AA}:1 AA`);

// possible
const posRgb = parseColor(bgPos);
assert.ok(posRgb, `hash-cell-possible bg "${bgPos}" must be a #hex or rgb() literal (var() not allowed)`);
const posRatio = contrast(WHITE, posRgb);
assert.ok(posRatio >= AA, `hash-cell-possible bg ${bgPos} vs #fff = ${posRatio.toFixed(2)}:1 < ${AA}:1 AA`);

// collision — bg is dynamic via classifyHashCell() gradient in analytics.js.
// Parse the gradient endpoints and verify BOTH ends clear AA against #fff.
// We extract the function body and `eval` it at t=0 and t=1 by walking the
// arithmetic — supports either shape: explicit `const cX = Math.round(A+B*t)`
// or inline `rgb(${Math.round(...)},${Math.round(...)},${Math.round(...)})`.
const analyticsJsPath = path.join(repoRoot, 'public', 'analytics.js');
const analyticsJs = fs.readFileSync(analyticsJsPath, 'utf8');
const classifyMatch = analyticsJs.match(/function\s+classifyHashCell[\s\S]*?\n\s{2}\}/);
assert.ok(classifyMatch, 'classifyHashCell function not found in analytics.js');
const classifyBody = classifyMatch[0];
assert.ok(/hash-cell-collision/.test(classifyBody), 'classifyHashCell missing hash-cell-collision branch');

// Pull the rgb(...) template inside the collision branch. The expression
// uses Math.round(...) which has nested parens, so a lazy regex won't work;
// scan forward and track paren depth from the opening `rgb(`.
const rgbStart = classifyBody.indexOf('background:rgb(');
assert.ok(rgbStart !== -1, 'classifyHashCell collision: background:rgb( not found');
let depth = 0;
let rgbEnd = -1;
for (let i = rgbStart + 'background:rgb('.length - 1; i < classifyBody.length; i++) {
  const ch = classifyBody[i];
  if (ch === '(') depth++;
  else if (ch === ')') { depth--; if (depth === 0) { rgbEnd = i; break; } }
}
assert.ok(rgbEnd !== -1, 'classifyHashCell collision: unbalanced rgb() parens');
const rgbExpr = classifyBody.slice(rgbStart + 'background:rgb('.length, rgbEnd); // e.g. "${cr},${cg},${cb}"

// Build an evaluator. If the template references cr/cg/cb, parse the
// `const cX = Math.round(A + (B)*t)` declarations above. Otherwise the
// template itself contains the arithmetic and we sandbox-eval it directly.
function evalRgbAt(t) {
  let exprWithT = rgbExpr.replace(/\$\{([^}]+)\}/g, (_, e) => '(' + e + ')');
  // Substitute cr/cg/cb if referenced.
  if (/\bc[rgb]\b/.test(exprWithT)) {
    for (const name of ['cr','cg','cb']) {
      const re = new RegExp('const\\s+' + name + '\\s*=\\s*([^;]+);');
      const m = classifyBody.match(re);
      if (!m) return null;
      exprWithT = exprWithT.replace(new RegExp('\\b' + name + '\\b', 'g'), '(' + m[1].trim() + ')');
    }
  }
  // Sandbox eval. Only allow Math, the loop var t, and arithmetic.
  // eslint-disable-next-line no-new-func
  const fn = new Function('t', 'Math', 'return [' + exprWithT + ']');
  return fn(t, Math);
}

const endpoints = [0, 1].map((t) => evalRgbAt(t));
assert.ok(endpoints[0] && endpoints[0].length === 3, 'collision gradient: failed to evaluate at t=0');
assert.ok(endpoints[1] && endpoints[1].length === 3, 'collision gradient: failed to evaluate at t=1');
const colRatios = endpoints.map((rgb) => contrast(WHITE, rgb));
assert.ok(colRatios[0] >= AA,
  `hash-cell-collision gradient t=0 rgb(${endpoints[0].join(',')}) vs #fff = ${colRatios[0].toFixed(2)}:1 < ${AA}:1 AA`);
assert.ok(colRatios[1] >= AA,
  `hash-cell-collision gradient t=1 rgb(${endpoints[1].join(',')}) vs #fff = ${colRatios[1].toFixed(2)}:1 < ${AA}:1 AA`);

console.log('\nM4 hash-cell semantic bg contrast (vs #fff):');
console.log('--------------------------------------------------');
console.log(`  [${takRatio>=AA?'PASS':'FAIL'}] hash-cell-taken     bg=${bgTak} ratio=${takRatio.toFixed(2)}:1`);
console.log(`  [${posRatio>=AA?'PASS':'FAIL'}] hash-cell-possible  bg=${bgPos} ratio=${posRatio.toFixed(2)}:1`);
console.log(`  [${colRatios[0]>=AA?'PASS':'FAIL'}] hash-cell-collision t=0 rgb(${endpoints[0].join(',')}) ratio=${colRatios[0].toFixed(2)}:1`);
console.log(`  [${colRatios[1]>=AA?'PASS':'FAIL'}] hash-cell-collision t=1 rgb(${endpoints[1].join(',')}) ratio=${colRatios[1].toFixed(2)}:1`);
console.log('--------------------------------------------------');

// --- 3b) /live VCR LIVE button — solid bg + #fff must clear AA -----------
// (#1681 r1 adv-#4: prior bg was --status-red = #ef4444 → 3.76:1 BLOCKER.
// Carve-out to red-700 (#b91c1c) achieves 6.47:1.)
const vcrLiveMatch = liveCss.match(/\.vcr-live-btn\s*\{([^}]+)\}/);
assert.ok(vcrLiveMatch, '.vcr-live-btn rule missing in live.css');
const vcrBg = bgOf(vcrLiveMatch[1]);
const vcrBgRgb = parseColor(vcrBg);
assert.ok(vcrBgRgb, `.vcr-live-btn bg "${vcrBg}" must be a #hex or rgb() literal (var() not allowed — needs own contrast budget vs #fff)`);
const vcrRatio = contrast(WHITE, vcrBgRgb);
assert.ok(vcrRatio >= AA, `.vcr-live-btn bg ${vcrBg} vs #fff = ${vcrRatio.toFixed(2)}:1 < ${AA}:1 AA`);
console.log(`  [${vcrRatio>=AA?'PASS':'FAIL'}] vcr-live-btn        bg=${vcrBg} ratio=${vcrRatio.toFixed(2)}:1`);
console.log('--------------------------------------------------');

// --- 4) final gate ---------------------------------------------------------

const totalFail = ruleFails + badgeFails;
assert.strictEqual(
  totalFail,
  0,
  `M4 per-route polish: ${ruleFails} typography + ${badgeFails} badge-contrast failures`
);

console.log('\nOK — M4 per-route polish gates pass.');
